<?php
namespace Tests\Unit\Domain\Hunts;use App\Domain\Combat\CombatResultStatus;use App\Domain\Combat\Data\CombatAction;use App\Domain\Hunts\Playback\HuntingPlaybackCalculator;use InvalidArgumentException;use PHPUnit\Framework\TestCase;
class HuntingPlaybackCalculatorTest extends TestCase{private function action($critical=false,$before=100,$after=90){return new CombatAction(1,'character:1','monster:1:1',75,1,true,5,1,$critical,$before-$after,$before,$after);}public function test_x1_x15_x2_and_final_phases(){$calculator=new HuntingPlaybackCalculator();$x1=$calculator->calculate([$this->action()],CombatResultStatus::CHARACTER_VICTORY,10000);$this->assertSame(1000,$x1->combatEventsDurationMs());$this->assertSame(500,$x1->resultRevealDurationMs());$this->assertSame(1000,$x1->lootRevealDurationMs());$this->assertSame(2500,$x1->playbackDurationMs());$this->assertSame(667,$calculator->calculate([$this->action()],CombatResultStatus::DRAW,15000)->combatEventsDurationMs());$this->assertSame(500,$calculator->calculate([$this->action()],CombatResultStatus::DRAW,20000)->combatEventsDurationMs());}public function test_critical_defeat_and_minimum_segment(){$calculator=new HuntingPlaybackCalculator();$critical=$calculator->calculate([$this->action(true,10,0)],CombatResultStatus::CHARACTER_VICTORY,10000);$this->assertSame(2000,$critical->combatEventsDurationMs());$fast=$calculator->calculate([$this->action()],CombatResultStatus::DRAW,PHP_INT_MAX);$this->assertSame(100,$fast->combatEventsDurationMs());}public function test_invalid_multiplier_and_millisecond_ceiling(){$calculator=new HuntingPlaybackCalculator();$this->assertSame(11,$calculator->millisecondsToCeilingSeconds(10301));$this->expectException(InvalidArgumentException::class);$calculator->calculate([$this->action()],CombatResultStatus::DRAW,0);}}
